

import React, { useEffect, useState, useRef } from 'react'

import { withRouter} from 'react-router-dom';
import { useSelector } from 'react-redux'

import loadable from '@loadable/component'


import {  deleteFsObj, getDispatch, getFs, LoadUAll, OpenModal, OpenWatchDialog, updFsObj, updFsObjByColl, updFsObjByField, updFsObjReservation, updObserveChanges  } from  '../../../actions/common'
import { selectCalendarObs, selectObserveAppointment, selectObserveChanges, selectObserveScreenWidth, setObsForm } from '../../../store/qvamarketsSlice';


import '../../../styles/_styles.css'
import { Icon_Cmpt, CheckBoxSlide_Cmpt } from '../../components';
import {  gen12CodeId, getBrowser, getPaymentsType, getProfileId, getStore, ObjectKeys, parseDate, updStore, updViewActive } from '../../../store/Util';

// updateCurrencyRate 


const CalendarAppointmets = loadable(() => import('../../components/Calendar_appointmets'))

const ConfirmAppointment = loadable(() => import('./confirmAppointment'))


const SendAppointment = loadable(() => import('./sendAppointment'))


const Icon2 = Icon_Cmpt();


const CheckBoxSlide =  CheckBoxSlide_Cmpt();

const RemitanceComponent = (props) => {
 

  const observe = useSelector(selectObserveAppointment);
  const widthScreen = useSelector(selectObserveScreenWidth);

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);

  
  const [view, setView] = useState(false);

  const [obs, set_obs] = useState(0);

  const calRef = useRef();
  
  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      updViewActive(65);
      if(!(getStore('userProfile') && getStore('userProfile').email)){
        updStore('singinView',1);
        updObserveChanges();
      }
      
      if(getStore('userProfile') && getStore('userProfile').email){
        if(!(getStore("userFs") && getStore("userFs")[(getStore('userProfile').id)])){
          updFsObjByColl("users",getStore('userProfile').id,{
              email: getStore('userProfile').email,
              name: getStore('userProfile').name,
              picture: getStore('userProfile').picture
          });
        }
      }

      setTimeout(()=>{
        window.scrollTo(0,0);
      },350);
      setTimeout(()=>setView(true),50);
    }
  });
  





  let userA = getBrowser();    
  let isMobile = userA.os === "Android" || userA.os === "iPhone" || getStore("outerWidth")<550 ;
  
  
  

  let pdate = getStore("date2makeAppId") && getStore("date2makeAppId").split("_");

  let nDt =  pdate  && new Date((pdate[1]*1+1)+'/'+pdate[2]+'/'+pdate[0]);



  let hd =  parseDate(nDt)



  const selectTime =  (v,_in09) => {
    updStore("time2makeAppId", v);
    updStore("hasReservationTime", _in09);
    set_obs(gen12CodeId())
  }


  const close =  (v) => {
    updStore("date2makeAppId",null);
    updStore("openTimeCard",null);
    updStore("time2makeAppId",null);
    updStore("hasReservationTime",null);
    updStore("paymentType",null)
    set_obs(gen12CodeId())
  }


  let aval_shift =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["shift"]

  const addAppp =  () => {
    /*
      let d2S = aval_shift;
      d2S[getStore("time2makeAppId")]["reserved"] = getProfileId()
      updFsObj(getStore("date2makeAppId"), "shift", d2S)
    */
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved", getProfileId() );
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift": getStore("time2makeAppId"),status:"confirmed"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
    
  }


  
  const cancelAppp =  () => {
    let d2S = aval_shift;
    d2S[getStore("time2makeAppId")]["reserved"] = null;
    //updFsObj(getStore("date2makeAppId"), "shift", d2S)

    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved");
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift":null,status:"canceled"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }
  
  return (
      <>
        <style>
        {`
        .palette{
          --base-color: rgb(21, 100, 191,1);
          --base-color-gradient: 21, 100, 191;
        }
        `}
        </style>
        <div className={`calendar_rose palette formContainer remitance ${isMobile?"is_mobile":"is_desktop"}`} style={{opacity:view?1:0}} >
          <div className={`formContainer `} style={{opacity:1}}>
            {view?
              <div className={`centerListCardProd calendar_rose paddBttm50 `}>

                  {!isMobile?
                    <CalendarAppointmets ref={calRef}/>
                  :
                  getStore("openTimeCard")?
                  null:
                    <CalendarAppointmets  ref={calRef}/>
                  }

                 

                  {getStore('isSpaOwner')?
                  <UpdCardComponent close={close}/>
                  : <TimeCardComponent  close={close}/>}
              </div>
            :null}
          </div>
        </div>
      </>
    );
}





export default withRouter(RemitanceComponent)
































const TimeCardComponent = (props) => {
 

  const observe = useSelector(selectObserveAppointment);
  const widthScreen = useSelector(selectObserveScreenWidth);

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);

  
  const [view, setView] = useState(false);

  const [obs, set_obs] = useState(0);

  const calRef = useRef();
  const mRecRef = useRef();
  
  useEffect(() => {
    
    if(!initialize){
      setInitialize(true);
      updViewActive(65);
      if(!(getStore('userProfile') && getStore('userProfile').email)){
        updStore('singinView',1);
        updObserveChanges();
      }
     

      setTimeout(()=>{
        window.scrollTo(0,0);
      },350);
      setTimeout(()=>setView(true),50);
     
    }
  });
  




  let userA = getBrowser();    
  let isMobile = userA.os === "Android" || userA.os === "iPhone" || getStore("outerWidth")<550 ;
  
  
  

  let pdate = getStore("date2makeAppId") && getStore("date2makeAppId").split("_");

  let nDt =  pdate  && new Date((pdate[1]*1+1)+'/'+pdate[2]+'/'+pdate[0]);



  let hd =  parseDate(nDt)



  const selectTime =  (v,_in09) => {
    updStore("time2makeAppId", v);
    updStore("hasReservationTime", _in09);
    set_obs(gen12CodeId())
  }


  const close =  (v) => {
    props.close()
  }


  let aval_shift =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["shift"]

  
  const Confirm =  () => {
    
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved", getProfileId() );
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".paymentType", getStore("paymentType")  );
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift": getStore("time2makeAppId"),status:"confirmed"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }

  const addAppp =  () => {
    let data = {};
    data['zIndex']=450;
    data['observeResize']=true;    
    data['props']={item:aval_shift[+getStore("time2makeAppId")], minHeight: '140px', overlay:true};
    data['content']=<SendAppointment confirm={Confirm}  />;
    OpenModal(data);
  }

  

  
  const cancelAppp =  () => {
    let d2S = aval_shift;
    d2S[getStore("time2makeAppId")]["reserved"] = null;
    //updFsObj(getStore("date2makeAppId"), "shift", d2S)

    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved");
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift":null,status:"canceled"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }

  const openDeepLink =  (l) => {
    window.open(l)
  }
  
  return (

    <div className="hour_appointment_wrapp" >
    <div className={`formContainer `} style={{opacity:getStore("openTimeCard")?1:0}}>
      {getStore("openTimeCard")?
      <div className="calendar_wrapper" >
        
          <div className="w100" >
            <div className={`_dsplFlx  space6Around `} >
              <div className={`flexSpace`}/>  
              <div className={`iconX`}  onClick={close}>  
                <Icon2 name={"Xclose"} color={"#42424"}/>
              </div>
            </div>
          
            <div className={`monthName `} >
              {`Horarios disponible`}
            </div>

            <div className={`selected_date`} >
              {hd}
            </div>
            <div className={`shift_app`} >
            {aval_shift &&  ObjectKeys(aval_shift).map((shi,_in09)=>{
              let isAvailable = !aval_shift[shi].reserved;
              let isRservedByUser = false;
              if(aval_shift[shi].reserved){
                isRservedByUser = aval_shift[shi].reserved === getProfileId();
               
                // && getStore("date2makeAppId") && getStore("recevationByUser") && getStore("recevationByUser")[getStore("date2makeAppId")];
                // isRservedByUser = rdata;
              }
              if(aval_shift[shi].isActive && (isAvailable || isRservedByUser)){
                let classNm = `hour_card ${getStore("time2makeAppId")===shi?"selected":""} ${isRservedByUser?"isUserReserved":""}  ${aval_shift[shi].isConfirmed?"isConfirmed":""}`
                return(
                  <div  className={classNm} key={shi+"_hour_card"} onClick={()=>selectTime(shi,isRservedByUser)}>
                    <div className={`_dsplFlx`}>
                      <Icon2 
                        name={isRservedByUser?"calendar":getStore("time2makeAppId")===shi?"success":"timer_outline"} 
                        color={"#7B1FA2"}
                      />
                      <div className={`lbl `}>
                        {`${aval_shift[shi].startTime}:00 - ${(aval_shift[shi].startTime)*1 + 2}:00`}
                      </div>
                    </div>
                    {isRservedByUser && !aval_shift[shi].isConfirmed && aval_shift[shi].paymentType && getPaymentsType()[aval_shift[shi].paymentType]?
                    <div className={aval_shift[shi].paymentType}>
                      <div className={`_dsplFlx`}>
                        <img src={getPaymentsType()[aval_shift[shi].paymentType].logo_150} alt={""}/>
                        <div className={`flexSpace`}/>
                        <div className={`_phoneNumber`} onClick={()=>getPaymentsType()[aval_shift[shi].paymentType].link && openDeepLink(getPaymentsType()[aval_shift[shi].paymentType].link)}>
                          <h5>{getPaymentsType()[aval_shift[shi].paymentType].tag}</h5>
                        </div>
                      </div>
                    </div> 
                    :null}
                  </div> 
                )
              }else return null
            })}
          </div>
          <div className={`formContainer `} style={{ "--frm-opacity": "opacity 550ms ease-in", opacity:getStore("time2makeAppId")?1:0}}>
            {getStore("time2makeAppId")?
            <div className={`txtOpa ${getStore("hasReservationTime")?"hasR":""}`} >
              <div className={`monthName`} >
                {getStore("hasReservationTime")?"Desea cancelar esta cita":`Deseas confirmar esta cita`}
              </div>
            <div  className={`hour_card selected btn_w150 _dsplFlx`} onClick={getStore("hasReservationTime")?cancelAppp:addAppp}>
              <Icon2 name={getStore("hasReservationTime")?"calendarX":"calendar"} color={"#1a73e8"}/>
              <div className={`lbl `}>
                {getStore("hasReservationTime")?"Cancelar":`Confirmar`}
              </div>
            </div>  
            </div>
            :null}
          </div>
        </div>
      </div>
      :null}
    </div>
    </div>
  )
}




































































const UpdCardComponent = (props) => {
 

  const observe = useSelector(selectObserveAppointment);
  const widthScreen = useSelector(selectObserveScreenWidth);

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);

  
  const [view, setView] = useState(false);

  const [obs, set_obs] = useState(0);

  const calRef = useRef();
  const mRecRef = useRef();



  let new_date = {
    "isActive":true,
    "shift":{
        "1":{
          "startTime":10,
          "isActive":true
        },
        "2":{
          "startTime":12,
          "isActive":true,
        },
        "3":{
          "startTime":14,
          "isActive":true,
        },
        "4":{
          "startTime":16,
          "isActive":true,
        },
        "5":{
          "startTime":18,
          "isActive":true,
        }
      }
  }

  const addDay = async (key,_in09) => {
    const docRef = getFs().doc(getFs().db, "appointments",getStore("date2makeAppId"));
    // let ss = await getFs().updateDoc(docRef,{[fld]: v});
    getFs().setDoc(docRef, new_date, { merge: true });
  }




  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      updViewActive(65);
      if(!(getStore('userProfile') && getStore('userProfile').email)){
        updStore('singinView',1);
        updObserveChanges();
      }
      setTimeout(()=>{
        window.scrollTo(0,0);
      },350);
      setTimeout(()=>setView(true),50);
    }
  });
  




  
  

  let pdate = getStore("date2makeAppId") && getStore("date2makeAppId").split("_");

  let nDt =  pdate  && new Date((pdate[1]*1+1)+'/'+pdate[2]+'/'+pdate[0]);



  let hd =  parseDate(nDt)

  let date_active =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["isActive"]

  let aval_shift =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["shift"]
 

  const selectTime =  (v,_in09) => {
    updStore("time2makeAppId", v);
    updStore("hasReservationTime", _in09);
    set_obs(gen12CodeId())
  }


  const close =  (v) => {
    props.close()
  }

 
  const addAppp =  () => {
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved", getProfileId() );
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift": getStore("time2makeAppId"),status:"confirmed"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }


  
  const cancelAppp =  () => {
    let d2S = aval_shift;
    d2S[getStore("time2makeAppId")]["reserved"] = null;
    //updFsObj(getStore("date2makeAppId"), "shift", d2S)

    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved");
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift":null,status:"canceled"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }
  
  const updActiveDate =  (v) => {

    if(getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")]){
      updFsObjByField("appointments/"+getStore("date2makeAppId"),"isActive", v );
    }
    else{
      addDay()
    }
  }




  return (

    <div className="hour_appointment_wrapp" >
    <div className={`formContainer `} style={{opacity:getStore("openTimeCard")?1:0}}>
      {getStore("openTimeCard")?
      <div className="calendar_wrapper" >
        
          <div className="w100" >
            <div className={`_dsplFlx  space6Around `} >
              <div className={`flexSpace`}/>  
              <div className={`iconX`}  onClick={close}>  
                <Icon2 name={"Xclose"} color={"#42424"}/>
              </div>
            </div>
          
            <div className={`monthName `} >
              {`Configurar Horarios`}
            </div>

            <div className={`selected_date _dsplFlx`} >
              {hd}
              <div className={`flexSpace`}/>
              <div className={`in_stock_switch _dsplFlx`}>
                <div  className={`in_stock_switch_btn dayactive_checkBoxSlide`}>
                  <CheckBoxSlide initvalue={date_active} keyCode={73} updChange={updActiveDate}/>
                </div>
              </div>
            </div>
            <div className={`shift_app`} >
            {aval_shift &&  ObjectKeys(aval_shift).map((shi)=>{
              return(
                <EditDayCardComponent shi={shi}  key={shi+"_hour_card"} />
              )
              
            })}
          </div>
          <div className={`formContainer `} style={{ "--frm-opacity": "opacity 550ms ease-in", opacity:getStore("time2makeAppId")?1:0}}>
            {getStore("time2makeAppId")?
            <div className={`txtOpa ${getStore("hasReservationTime")?"hasR":""}`} >
              <div className={`monthName`} >
                {getStore("hasReservationTime")?"Desea cancelar esta cita":`Deseas confirmar esta cita`}
              </div>
            <div  className={`hour_card selected btn_w150 _dsplFlx`} onClick={getStore("hasReservationTime")?cancelAppp:addAppp}>
              <Icon2 name={getStore("hasReservationTime")?"calendarX":"calendar"} color={"#1a73e8"}/>
              <div className={`lbl `}>
                {getStore("hasReservationTime")?"Cancelar":`Confirmar`}
              </div>
            </div>  
            </div>
            :null}
          </div>
        </div>
      </div>
      :null}
    </div>
    </div>
  )
}







const EditDayCardComponent = (props) => {
 
  const { shi} = props; 
  const observe = useSelector(selectObserveAppointment);
  const widthScreen = useSelector(selectObserveScreenWidth);

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);
  const [editView, setEditView] = useState(false);

  let isRservedByUser = null;
  let isRvByUserD = {};

  
  let aval_shift =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["shift"]
 
  
  if(aval_shift[shi].reserved){
    isRservedByUser = true;
    isRvByUserD = getStore("userFs")?getStore("userFs")[aval_shift[shi].reserved]:{};
  }

  
  const updActiveShift =  (v) => {
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+shi+".isActive", v);
  }

  const updStartTime =  (v) => {
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+shi+".startTime", aval_shift[shi].startTime+v);
  }

  let classNm = `hour_card ${getStore("time2makeAppId")===shi?"selected":""} ${isRservedByUser?"isUserReserved":""}  ${aval_shift[shi].isConfirmed?"isConfirmed":""}`
  
  const openConfirm = () => {
    let data = {};
    data['zIndex']=450;
    data['observeResize']=true;    
    data['props']={item:aval_shift[shi], userId:  isRservedByUser && isRvByUserD.name , minHeight: '140px', overlay:true};
    data['content']=<ConfirmAppointment confirm={Confirm} reject={_reject} />;
    OpenModal(data);
  }

  const Confirm = () => {
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+shi+".isConfirmed", true);
  }
  const _reject = () => {
    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+shi+".isConfirmed");
    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+shi+".reserved");
  }

  return (
          <div  
            className={classNm} 
           
            // onClick={()=>selectTime(shi,isRservedByUser)}
          >
            
            <style>
                  {`
                  .palette_checkBoxSlide{
                  
                  }
                  `}
            </style>
            <div className={`_dsplFlx`}>
            {!editView?
              <Icon2 
                name={isRservedByUser?"calendar":getStore("time2makeAppId")===shi?"success":"timer_outline"} 
                color={"#7B1FA2"}
              />
              :null}
              {editView?
              <div className={`_dsplFlx`}>
                <div onClick={()=>updStartTime(-1)} >
                  <Icon2 
                    name={"arrow_down"} 
                    color={"#262626"}
                  />
                </div>
                <div className={`lbl `}>
                  {`${aval_shift[shi].startTime}:00 - ${(aval_shift[shi].startTime)*1 + 2}:00`}
                </div>
                <div onClick={()=>updStartTime(1)} >
                  <Icon2
                    name={"arrow_up"} 
                    color={"#262626"}
                  />
                </div>
              </div>
              :
              <div className={`lbl `} onClick={()=>setEditView(true)}>
                {`${aval_shift[shi].startTime}:00 - ${(aval_shift[shi].startTime)*1 + 2}:00`}
              </div>
              }
              
              <div className={`flexSpace`}/>
              {editView?
              <div onClick={()=>setEditView(false)} >
                <Icon2 
                  name={"cancel"} 
                  color={"#262626"}
                />
              </div>
              :
              <div  className={`in_stock_switch_btn palette_checkBoxSlide`}>
                
                <CheckBoxSlide initvalue={aval_shift[shi].isActive} keyCode={77} updChange={updActiveShift}/>
              </div>
              }
            </div>
            <div className={`user_appointment_detail _dsplFlx`}   onClick={openConfirm} > 
              {isRservedByUser?isRvByUserD && isRvByUserD.name:""}
            </div>
          </div>
  )
}

/// agregar un modal al usuario para confirmar o rechazar la cita y en la base de datos poner un campo confirmado sino marcarlo como pendiente